#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;
const double eps=1e-7;

int n,h[N],w[N],k[N];
long long f[N],sum,b[N];

struct Node{
    mutable double l,r;
    int v;
    bool operator<(Node x)const{
        if(!x.v || !v)
            return l<x.l;
        return k[v]>k[x.v];
    }
};

set<Node> odt;

int cmp(double x,int u,int v){
    double ya=k[u]*x+b[u],yb=k[v]*x+b[v];
    if(fabs(ya-yb)<=eps)
        return 0;
    if(ya<yb)
        return -1;
    return 1;
}

void Insert(int x){
    auto it=odt.lower_bound({0,0,x});
    if(it->v>n)
        it--;
    //printf("find %.2lf %2.lf %d\n",it->l,it->r,it->v);
    if(cmp(it->l,x,it->v)==1 && cmp(it->r,x,it->v)==1)
        return;
    auto itl=it,itr=it;
    while(itr->v<=n && cmp(itr->r,x,itr->v)<1)
        itr++;
    while(itl->v<=n && cmp(itl->l,x,itr->v)<1)
        itl--;

    //printf("check %d %d\n",itl->v,itr->v);
    double l=itl->l,r=itl->r;
    if(itl->v>n)
        l=r;
    Node tmp;
    while(r-l>eps){
        double mid=(l+r)/2;
        if(cmp(mid,x,itl->v)<1)
            r=mid;
        else
            l=mid;
    }

    tmp.l=l;
    itl->r=tmp.l;
    l=itr->l,r=itr->r;
    if(itr->v>n)
        r=l;
    while(r-l>eps){
        double mid=(l+r)/2;
        if(cmp(mid,x,itr->v)<1)
            l=mid;
        else
            r=mid;
    }
    tmp.r=l;
    tmp.v=x;
    itr->l=tmp.r;
    itl++;
    //printf("insert %.2lf %.2lf\n",tmp.l,tmp.r);
    odt.erase(itl,itr);
    odt.insert(tmp);
}

int query(int x){
    auto it=odt.upper_bound({x,0,0});
    it--;
    //printf("%.2lf %.2lf\n",it->l,it->r);
    return it->v;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&h[i]);
    for(int i=1;i<=n;i++){
        scanf("%d",&w[i]);
        sum+=w[i];
    }
    f[1]=-w[1];
    k[1]=-2*h[1],b[1]=1ll*h[1]*h[1]+f[1];
    k[n+1]=1e9,b[n+1]=-1e18;
    k[n+2]=-1e9,b[n+2]=-1e18;
    odt.insert({0,2e6,1});
    odt.insert({-10,0,n+1});
    odt.insert({2e6,2e6+10,n+2});
    for(int i=2;i<=n;i++){
        int p=query(h[i]);
        //printf("%d %d\n",i,p);
        f[i]=f[p]+1ll*(h[i]-h[p])*(h[i]-h[p])-w[i];
        k[i]=-2*h[i];
        b[i]=1ll*h[i]*h[i]+f[i];
        //printf("(%d, %d, %lld, %lld)\n",i,k[i],b[i],f[i]);
        Insert(i);
    }
    printf("%lld",f[n]+sum);
    return 0;
}
